import { createClient } from '@/utils/supabase/server'
import { NextResponse } from 'next/server'

export async function GET(request: Request, props: { params: Promise<{ id: string }> }) {
  const params = await props.params;
  const id = params.id;
  const supabase = await createClient()

  const { data, error } = await supabase
    .from('qr_codes')
    .select('*')
    .eq('id', id)
    .single()

  if (error) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }

  return NextResponse.json(data)
}

export async function PUT(request: Request, props: { params: Promise<{ id: string }> }) {
  const params = await props.params;
  const id = params.id;
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  try {
    const updates = await request.json()
    // Don't allow changing the ID or short_id
    delete updates.id
    delete updates.short_id
    delete updates.user_id

    const { data, error } = await supabase
      .from('qr_codes')
      .update({
        ...updates,
        updated_at: new Date().toISOString()
      })
      .eq('id', id)
      .eq('user_id', user.id)
      .select()
      .single()

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 })
    }

    return NextResponse.json(data)
  } catch (err) {
    return NextResponse.json({ error: 'Invalid request' }, { status: 400 })
  }
}

export async function DELETE(request: Request, props: { params: Promise<{ id: string }> }) {
  const params = await props.params;
  const id = params.id;
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  const { error } = await supabase
    .from('qr_codes')
    .delete()
    .eq('id', id)
    .eq('user_id', user.id)

  if (error) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }

  return NextResponse.json({ success: true })
}

import { createClient } from '@/utils/supabase/server'
import { NextResponse } from 'next/server'
import crypto from 'crypto'

export async function GET(request: Request) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  const { data, error } = await supabase
    .from('qr_codes')
    .select('*')
    .eq('user_id', user.id)
    .order('created_at', { ascending: false })

  if (error) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }

  return NextResponse.json(data)
}

export async function POST(request: Request) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  try {
    const { original_url, title } = await request.json()
    // Generate a unique 6-character short ID
    // Check uniqueness ideally, but random bytes should be unique practically
    let short_id = crypto.randomBytes(3).toString('hex')

    const { data, error } = await supabase
      .from('qr_codes')
      .insert({
        user_id: user.id,
        short_id,
        original_url,
        title,
      })
      .select()
      .single()

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 })
    }

    return NextResponse.json(data)
  } catch (err) {
    return NextResponse.json({ error: 'Invalid request' }, { status: 400 })
  }
}

'use client'

import { useState, useEffect, use } from 'react'
import { useRouter } from 'next/navigation'
import { Button, buttonVariants } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Switch } from '@/components/ui/switch'
import { toast } from 'sonner'
import Link from 'next/link'
import { ArrowLeft, ExternalLink, Download } from 'lucide-react'
import QRCode from 'qrcode'

export default function QRCodeDetailsPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params)
  const [code, setCode] = useState<any>(null)
  const [title, setTitle] = useState('')
  const [originalUrl, setOriginalUrl] = useState('')
  const [isActive, setIsActive] = useState(true)
  const [qrDataUrl, setQrDataUrl] = useState('')
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const router = useRouter()

  useEffect(() => {
    const fetchCode = async () => {
      try {
        const res = await fetch(`/api/codes/${id}`)
        if (res.ok) {
          const data = await res.json()
          setCode(data)
          setTitle(data.title || '')
          setOriginalUrl(data.original_url || '')
          setIsActive(data.is_active)

          // Generate QR code data URL using the redirect route
          const redirectUrl = `${window.location.origin}/qr/${data.short_id}`
          const dataUrl = await QRCode.toDataURL(redirectUrl, { width: 300, margin: 2 })
          setQrDataUrl(dataUrl)
        } else {
          toast.error('Failed to load QR code')
          router.push('/dashboard/qrcodes')
        }
      } catch (e) {
        toast.error('An error occurred')
      } finally {
        setLoading(false)
      }
    }
    fetchCode()
  }, [id, router])

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault()
    setSaving(true)

    try {
      const res = await fetch(`/api/codes/${id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, original_url: originalUrl, is_active: isActive })
      })

      if (res.ok) {
        toast.success('QR Code updated!')
        setCode((prev: any) => ({ ...prev, title, original_url: originalUrl, is_active: isActive }))
      } else {
        const error = await res.json()
        toast.error(error.message || 'Failed to update')
      }
    } catch (e) {
      toast.error('An error occurred')
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return <div className="p-8 text-center text-gray-500">Loading...</div>
  }

  return (
    <div className="space-y-6 max-w-4xl mx-auto">
      <div className="flex items-center gap-4">
        <Link href="/dashboard/qrcodes" className={buttonVariants({ variant: 'ghost', size: 'icon' })}>
            <ArrowLeft className="h-5 w-5" />
        </Link>
        <div>
          <h1 className="text-2xl font-bold tracking-tight">{code?.title || 'QR Code Details'}</h1>
          <p className="text-muted-foreground">ID: {code?.short_id}</p>
        </div>
      </div>

      <div className="grid gap-6 md:grid-cols-2">
        <Card>
          <CardHeader>
            <CardTitle>Edit Details</CardTitle>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleUpdate} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="title">Title</Label>
                <Input 
                  id="title" 
                  value={title} 
                  onChange={(e) => setTitle(e.target.value)} 
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="url">Destination URL</Label>
                <Input 
                  id="url" 
                  type="url" 
                  value={originalUrl} 
                  onChange={(e) => setOriginalUrl(e.target.value)} 
                  required 
                />
              </div>
              <div className="flex items-center space-x-2 pt-2">
                <Switch 
                  id="active" 
                  checked={isActive} 
                  onCheckedChange={setIsActive} 
                />
                <Label htmlFor="active">Active (Redirect enabled)</Label>
              </div>
              <div className="pt-4 flex justify-end">
                <Button type="submit" disabled={saving}>
                  {saving ? 'Saving...' : 'Save Changes'}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>QR Code Image</CardTitle>
            <CardDescription>Scan to test the redirection</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col items-center space-y-4">
            {qrDataUrl && (
              <div className="p-4 bg-white rounded-lg border shadow-sm">
                <img src={qrDataUrl} alt="QR Code" className="w-48 h-48" />
              </div>
            )}
            <div className="flex gap-2 w-full justify-center">
              <a href={qrDataUrl} download={`qr-${code?.short_id}.png`} className={buttonVariants({ variant: 'outline' })}>
                  <Download className="mr-2 h-4 w-4" /> Download
              </a>
              <a href={`/qr/${code?.short_id}`} target="_blank" rel="noopener noreferrer" className={buttonVariants({ variant: 'outline' })}>
                  <ExternalLink className="mr-2 h-4 w-4" /> Test Link
              </a>
            </div>
            <div className="text-sm text-center text-muted-foreground w-full p-4 bg-gray-50 rounded-md break-all">
              {`${typeof window !== 'undefined' ? window.location.origin : ''}/qr/${code?.short_id}`}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}

