  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { toast } from 'sonner'

export default function QRCodesPage() {
  const [codes, setCodes] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  const fetchCodes = async () => {
    try {
      const res = await fetch('/api/codes')
      if (res.ok) {
        const data = await res.json()
        setCodes(data)
      }
    } catch (e) {
      toast.error('Failed to load QR codes')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchCodes()
  }, [])

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this QR code?')) return

    try {
      const res = await fetch(`/api/codes/${id}`, {
        method: 'DELETE',
      })
      if (res.ok) {
        toast.success('QR Code deleted')
        fetchCodes()
      } else {
        toast.error('Failed to delete')
      }
    } catch (e) {
      toast.error('An error occurred')
    }
  }

  const renderQRGrid = () => {
    return (
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Title</TableHead>
            <TableHead>Short ID</TableHead>
            <TableHead>Destination URL</TableHead>
            <TableHead>Scans</TableHead>
            <TableHead>Status</TableHead>
            <TableHead className="text-right">Actions</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {codes.map((code) => (
            <TableRow key={code.id}>
              <TableCell className="font-medium">{code.title || 'Untitled'}</TableCell>
              <TableCell>{code.short_id}</TableCell>
              <TableCell className="max-w-[200px] truncate" title={code.original_url}>{code.original_url}</TableCell>
              <TableCell>{code.scan_count}</TableCell>
              <TableCell>
                <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${
                  code.is_active ? 'bg-green-50 text-green-700' : 'bg-gray-100 text-gray-700'
                }`}>
                  {code.is_active ? 'Active' : 'Inactive'}
                </span>
              </TableCell>
              <TableCell className="text-right space-x-2">
                <Link href={`/dashboard/qrcodes/${code.id}`} className={buttonVariants({ variant: 'outline', size: 'icon' })}>
                    <Edit className="h-4 w-4" />
                </Link>
                <Button variant="destructive" size="icon" onClick={() => handleDelete(code.id)}>
                  <Trash2 className="h-4 w-4" />
                </Button>
              </TableCell>
            </TableRow>
          ))}
          {codes.length === 0 && (
            <TableRow>
              <TableCell colSpan={6} className="text-center py-8 text-gray-500">
                No QR codes found. Create your first one!
              </TableCell>
            </TableRow>
          )}
        </TableBody>
      </Table>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">QR Codes</h1>
          <p className="text-muted-foreground">Manage your dynamic QR codes</p>
        </div>
        <Link href="/dashboard/qrcodes/new" className={buttonVariants()}>
            <Plus className="mr-2 h-4 w-4" />
            Create QR Code
        </Link>
      </div>

      <Card>
        <CardContent className="p-0">
          {loading ? (
            <div className="p-8 text-center text-gray-500">Loading...</div>
          ) : renderQRGrid()}
        </CardContent>
      </Card>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { createClient } from '@/utils/supabase/client'
import { useRouter } from 'next/navigation'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
